<?php
namespace App\Controllers;
use App\Core\Auth;use App\Core\Database;use App\Core\View;use App\Services\AuditService;
final class InventoryController{
 public function index():void{Auth::requireRole('owner','office','crew_leader');$rows=Database::connection()->query('SELECT * FROM inventory_items ORDER BY category,name')->fetchAll();View::render('portal/inventory/index',['title'=>'Inventory','items'=>$rows],'portal');}
 public function store():void{Auth::requireRole('owner','office');verify_csrf();$s=Database::connection()->prepare('INSERT INTO inventory_items(sku,name,category,quantity,reorder_level,unit,unit_cost,storage_location) VALUES(?,?,?,?,?,?,?,?)');$s->execute([trim($_POST['sku'])?:null,trim($_POST['name']),trim($_POST['category']??''),(float)($_POST['quantity']??0),(float)($_POST['reorder_level']??0),trim($_POST['unit']??'each'),$_POST['unit_cost']!==''?(float)$_POST['unit_cost']:null,trim($_POST['storage_location']??'')]);$id=(int)Database::connection()->lastInsertId();Database::connection()->prepare('UPDATE inventory_items SET asset_tag=?,qr_token=? WHERE id=?')->execute(['RB-EQP-'.str_pad((string)$id,5,'0',STR_PAD_LEFT),bin2hex(random_bytes(16)),$id]);AuditService::log('inventory.created','inventory_item',$id);flash('success','Inventory item added.');redirect('/portal/inventory');}
 public function transact(string $id):void{Auth::requireRole('owner','office','crew_leader');verify_csrf();$type=$_POST['transaction_type']??'adjust';$qty=(float)($_POST['quantity']??0);$delta=$type==='use'?-abs($qty):($type==='receive'?abs($qty):$qty);$db=Database::connection();$db->beginTransaction();$db->prepare('UPDATE inventory_items SET quantity=quantity+? WHERE id=?')->execute([$delta,(int)$id]);$db->prepare('INSERT INTO inventory_transactions(inventory_item_id,transaction_type,quantity,notes,created_by) VALUES(?,?,?,?,?)')->execute([(int)$id,$type,$delta,trim($_POST['notes']??''),Auth::id()]);$db->commit();flash('success','Inventory updated.');redirect('/portal/inventory');}
}
